import React from "react";
import styles from "./button-add.module.css";
import { useDispatch } from "react-redux";
import { addItem } from "../../app/cartSlice";

interface ButtonAddProps {
  product: {
    id: number;
    img: string;
    name: string;
    price: number;
    quantity: number;
  };
}

const ButtonAdd: React.FC<ButtonAddProps> = ({ product }) => {

  const dispatch = useDispatch();

  const cartItem = {
    id: product.id,
    name: product.name, // Assuming title is equivalent to name
    price: product.price,
    img: product.img, // Assuming imgSrc is equivalent to img
  };

  const handleAddToCart = () => {
    console.log("Adding item to cart:", cartItem);
    dispatch(addItem(cartItem));
  };

  return (
    <button className={styles.button_add} onClick={handleAddToCart}>
      <img
        src={`${process.env.PUBLIC_URL}/images/Cart-white.svg`}
        alt="cart-logo"
        width={24}
        height={24}
      />
      <span className={styles.button_text}>"+ Add to cart"</span>
    </button>
  );
};

export default ButtonAdd;

